import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { Upload, ArrowLeft, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtistForm = () => {
  const navigate = useNavigate();
  const [file, setFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);

  const handleImport = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return toast.error("Please select an Excel file");

    setLoading(true);
    try {
      await AdminService.importData('artist', file);
      toast.success("Artists Imported Successfully");
      navigate('/admin/artists');
    } catch (err: any) {
      toast.error("Import Failed: Check file format");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-700">
      <button 
        onClick={() => navigate(-1)} 
        className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-primary transition-colors"
      >
        <ArrowLeft size={14} /> Back to Registry
      </button>

      <div className="bg-white dark:bg-[#0f0f0f] rounded-[3rem] p-12 border border-gray-100 dark:border-white/5 shadow-2xl">
        <div className="mb-10">
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Register <span className="text-primary">Artists</span></h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Bulk Excel Synchronization</p>
        </div>

        <form onSubmit={handleImport} className="space-y-6">
          <div className="group relative border-2 border-dashed border-gray-200 dark:border-white/10 rounded-[2rem] p-16 transition-all hover:border-primary/50 flex flex-col items-center justify-center gap-4 bg-gray-50/50 dark:bg-white/2">
            <input 
              type="file" 
              accept=".xlsx, .xls, .csv"
              onChange={(e) => setFile(e.target.files?.[0] || null)}
              className="absolute inset-0 opacity-0 cursor-pointer"
            />
            <div className="p-5 bg-white dark:bg-white/5 rounded-2xl shadow-sm group-hover:scale-110 transition-transform">
              <Upload className="text-primary" size={32} />
            </div>
            <div className="text-center">
              <p className="font-black uppercase text-xs italic">
                {file ? file.name : "Drop Excel Sheet or Click to Browse"}
              </p>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-2">Maximum file size: 10MB</p>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-black text-white py-6 rounded-2xl font-black uppercase tracking-[0.2em] text-xs flex items-center justify-center gap-3 hover:bg-primary transition-all disabled:opacity-50"
          >
            {loading ? "Processing Archive..." : <><Save size={18} /> Commit to Archive</>}
          </button>
        </form>
      </div>

      <div className="bg-primary/5 border border-primary/10 rounded-2xl p-6">
        <h4 className="text-primary font-black uppercase text-[10px] tracking-widest mb-2">Instructions</h4>
        <p className="text-gray-500 text-[10px] font-bold uppercase leading-relaxed">
          Ensure your Excel columns match the schema: <span className="text-white">Artist_ID, Name_En, Name_Ar, Bio_En, Image.</span> 
          Artist ID must be unique.
        </p>
      </div>
    </div>
  );
};
